on conflict (manufacturer, lower(email)) where email is not null do update set
  first_name = excluded.first_name,
  last_name  = excluded.last_name,
  full_name  = excluded.full_name,
  phone      = excluded.phone,
  cell       = excluded.cell,
  title      = excluded.title,
  territory  = excluded.territory,
  region     = excluded.region,
  raw        = excluded.raw,
  updated_at = now();

-- 7 contacts without email (delete-and-insert)
delete from public.manufacturer_contacts where email is null and manufacturer = 'Duro-Last' and coalesce(first_name,'') = null and coalesce(last_name,'') = 'Z-Open';
delete from public.manufacturer_contacts where email is null and manufacturer = 'GAF' and coalesce(first_name,'') = 'Unknown' and coalesce(last_name,'') = null;
delete from public.manufacturer_contacts where email is null and manufacturer = 'Sika' and coalesce(first_name,'') = 'Open' and coalesce(last_name,'') = 'Open';
delete from public.manufacturer_contacts where email is null and manufacturer = 'Unirac' and coalesce(first_name,'') = 'Griffin' and coalesce(last_name,'') = 'Phelps';

